import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
/**
 * A session-ended carrying `reason: "never-connected"` (the window never
 * surfaced; synthesized by the connect watchdog / daemon reaper) must reach the
 * wrapper commands' terminal stdout events, so an agent can offer a retry
 * instead of reading the terminal as a user abort.
 */
const emitted = [];
vi.mock("../output.js", () => ({
    emitJson: (obj) => {
        emitted.push(obj);
    },
    blockingNote: (until) => `BLOCKING: ${until}`,
}));
vi.mock("../config.js", () => ({
    getConfig: () => ({ serviceUrl: "https://test.invalid", apiKey: null }),
    hasCredentials: () => false,
}));
vi.mock("../analytics.js", () => ({
    reportHandoff: vi.fn().mockResolvedValue(undefined),
}));
let capturedOnEvent = null;
const mockOpenStudioTo = vi.fn(async (_path, opts) => {
    capturedOnEvent = opts.onEvent ?? null;
    let resolveDone = () => { };
    const done = new Promise((resolve) => {
        resolveDone = resolve;
    });
    // Deliver the terminal event on the next tick, after the command has
    // installed its abort handle.
    setTimeout(() => {
        capturedOnEvent?.({
            type: "studio:session-ended",
            data: { reason: "never-connected" },
        });
    }, 0);
    return {
        sessionId: "sess-1",
        serviceUrl: "https://test.invalid",
        apiKey: "key",
        opened: true,
        persistent: true,
        abort: () => resolveDone(),
        done,
    };
});
vi.mock("./openStudioTo.js", () => ({
    openStudioTo: (...args) => mockOpenStudioTo(...args),
    handleStudioError: (err) => {
        throw err;
    },
}));
const DATASET_ID = "11111111-1111-4111-8111-111111111111";
const PLAN_ID = "22222222-2222-4222-8222-222222222222";
let savedArgv;
const stdoutLines = [];
beforeEach(() => {
    emitted.length = 0;
    stdoutLines.length = 0;
    capturedOnEvent = null;
    savedArgv = process.argv;
    vi.spyOn(process, "exit").mockImplementation((() => { }));
    vi.spyOn(console, "error").mockImplementation(() => { });
    vi.spyOn(process.stdout, "write").mockImplementation(((chunk) => {
        stdoutLines.push(String(chunk));
        return true;
    }));
});
afterEach(() => {
    process.argv = savedArgv;
    vi.restoreAllMocks();
    mockOpenStudioTo.mockClear();
});
describe("never-connected reason pass-through", () => {
    it("startDataset forwards the reason on its cancelled event", async () => {
        process.argv = ["node", "startDataset.js", "my-fn", DATASET_ID];
        const { runStartDataset } = await import("./startDataset.js");
        await runStartDataset({}, "0.0.0-test");
        expect(emitted).toContainEqual({
            event: "cancelled",
            status: "cancelled",
            reason: "never-connected",
        });
    });
    it("openTracePlan forwards the reason on its cancelled event", async () => {
        process.argv = ["node", "openTracePlan.js", PLAN_ID];
        const { runOpenTracePlan } = await import("./openTracePlan.js");
        await runOpenTracePlan({}, "0.0.0-test");
        // openTracePlan writes its own stdout lines; parse the spied writes.
        const lines = stdoutLines
            .map((line) => line.trim())
            .filter((line) => line.startsWith("{"))
            .map((line) => JSON.parse(line));
        expect(lines).toContainEqual({
            event: "cancelled",
            planId: PLAN_ID,
            reason: "never-connected",
        });
    });
});
